8	    expect(quote({ items: [] })).toEqual({ premium: 5 });
9	  });
10	  it("single sword → premium 105 G (100 base + 5 fee), neutral customer", () => {
11	    expect(quote({ items: [{ type: "sword" }] })).toEqual({ premium: 105 });
12	  });
13	  it("single amulet → premium 65 G (60 base + 5 fee)", () => {
14	    expect(quote({ items: [{ type: "amulet" }] })).toEqual({ premium: 65 });
15	  });
16	  it.todo("single staff → premium 85 G (80 base + 5 fee)");
17	  it.todo("single potion → premium 45 G (40 base + 5 fee)");
18	  it.todo("single rune component → premium 30 G (25 base + 5 fee)");
19	
20	  // --- Quote: component block (R2) ---
21	  it.todo("2 runes → 50 G base premium (no block)");
22	  it.todo("3 runes → 60 G base premium (block of exactly 3)");
23	  it.todo("4 runes → 100 G base premium (no block; block requires exactly 3)");
24	  it.todo("7 runes → 175 G base premium (7×25; not exactly 3, all singles)");
