31	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
32	  it.todo("cursed sword with enchantment ≥5 → both curse and high-enchantment surcharges apply");
33	
34	  // --- Quote: policy-wide modifiers (R3) ---
35	  it.todo("customer with exactly 2 years → 20% loyalty discount applies to policy base");
36	  it.todo("first insurance → +10% surcharge per item base premium");
37	  it.todo("second quote in scenario → 15% follow-up discount applies policy-wide");
38	
39	  // --- Quote: modifier scope on multi-item policies (R3) ---
40	  it.todo("cursed sword (base 100) + plain amulet (base 60) → 210 G before fee (curse on sword base only)");
41	
42	  // --- Quote: integration examples (R3) ---
43	  it.todo("newcomer (0 years) cursed sword steel ench 3 → premium 165 G (100+50 curse+10 first +5 fee)");
44	  it.todo("3-year customer 2nd quote, cursed sword steel ench 7 → premium 160 G (100+50+30-20+10-15+5)");
45	
46	  // --- Quote: rounding (R4) ---
47	  it.todo("premium yielding 197.5 G → final premium 198 G (rounded up)");
48	
49	  // --- Claim: standard reimbursement (R5) ---
50	  it.todo("steel sword ench 3, damage 500 → payout 400 G (full minus 100 deductible)");
51	  it.todo("rune (value 250), damage 200 → payout 100 G (no clause; minus 100 deductible)");
52	
53	  // --- Claim: deductible per damage event (R5) ---
54	  it.todo("dragon attack damages sword (500) + amulet (300) → payout 600 G (deductible per item)");
55	
56	  // --- Claim: enchantment threshold vs dragon material (R5) ---
57	  it.todo("dragon sword ench exactly 8, damage 1000 → payout 400 G (50% rule wins, then deductible)");
58	  it.todo("dragon sword ench 9, damage 1000 → payout 400 G (both clauses, 50% wins: 500−100)");
59	  it.todo("dragon sword ench 5, damage 800 → payout 700 G (dragon clause only: 800−100)");
60	  it.todo("steel sword ench 9, damage 1000 → payout 400 G (high-enchantment only: 500−100)");
